1	import { Fragment, type ReactNode, createElement, useEffect } from "react";
2	import {
3	  DEFAULT_MODEL_BY_PROVIDER,
4	  type ProviderKind,
5	  ThreadId,
6	  type OrchestrationReadModel,
7	  type OrchestrationSessionStatus,
8	} from "@t3tools/contracts";
9	import {
10	  getModelOptions,
11	  normalizeModelSlug,
12	  resolveModelSlug,
13	  resolveModelSlugForProvider,
14	} from "@t3tools/shared/model";
15	import { create } from "zustand";
16	import { type ChatMessage, type Project, type Thread } from "./types";
17	
18	// ── State ────────────────────────────────────────────────────────────
19	
20	export interface AppState {
21	  projects: Project[];
22	  threads: Thread[];
23	  threadsHydrated: boolean;
24	}
25	
26	const PERSISTED_STATE_KEY = "t3code:renderer-state:v8";
27	const LEGACY_PERSISTED_STATE_KEYS = [
28	  "t3code:renderer-state:v7",
29	  "t3code:renderer-state:v6",
30	  "t3code:renderer-state:v5",
31	  "t3code:renderer-state:v4",
32	  "t3code:renderer-state:v3",
33	  "codething:renderer-state:v4",
34	  "codething:renderer-state:v3",
35	  "codething:renderer-state:v2",
36	  "codething:renderer-state:v1",
37	] as const;
38	
39	const initialState: AppState = {
40	  projects: [],
41	  threads: [],
42	  threadsHydrated: false,
43	};
44	const persistedExpandedProjectCwds = new Set<string>();
45	
46	// ── Persist helpers ──────────────────────────────────────────────────
47	
48	function readPersistedState(): AppState {
49	  if (typeof window === "undefined") return initialState;
50	  try {
51	    const raw = window.localStorage.getItem(PERSISTED_STATE_KEY);
52	    if (!raw) return initialState;
53	    const parsed = JSON.parse(raw) as { expandedProjectCwds?: string[] };
54	    persistedExpandedProjectCwds.clear();
55	    for (const cwd of parsed.expandedProjectCwds ?? []) {
56	      if (typeof cwd === "string" && cwd.length > 0) {
57	        persistedExpandedProjectCwds.add(cwd);
58	      }
59	    }
60	    return { ...initialState };
61	  } catch {
62	    return initialState;
63	  }
64	}
65	
66	function persistState(state: AppState): void {
67	  if (typeof window === "undefined") return;
68	  try {
69	    window.localStorage.setItem(
70	      PERSISTED_STATE_KEY,
71	      JSON.stringify({
72	        expandedProjectCwds: state.projects
73	          .filter((project) => project.expanded)
74	          .map((project) => project.cwd),
75	      }),
76	    );
77	    for (const legacyKey of LEGACY_PERSISTED_STATE_KEYS) {
78	      window.localStorage.removeItem(legacyKey);
79	    }
80	  } catch {
81	    // Ignore quota/storage errors to avoid breaking chat UX.
82	  }
83	}
84	
85	// ── Pure helpers ──────────────────────────────────────────────────────
86	
87	function updateThread(
88	  threads: Thread[],
89	  threadId: ThreadId,
90	  updater: (t: Thread) => Thread,
91	): Thread[] {
92	  let changed = false;
93	  const next = threads.map((t) => {
94	    if (t.id !== threadId) return t;
95	    const updated = updater(t);
96	    if (updated !== t) changed = true;
97	    return updated;
98	  });
99	  return changed ? next : threads;
100	}
101	
102	function mapProjectsFromReadModel(
103	  incoming: OrchestrationReadModel["projects"],
104	  previous: Project[],
105	): Project[] {
106	  return incoming.map((project) => {
107	    const existing =
108	      previous.find((entry) => entry.id === project.id) ??
109	      previous.find((entry) => entry.cwd === project.workspaceRoot);
110	    return {
111	      id: project.id,
112	      name: project.title,
113	      cwd: project.workspaceRoot,
114	      model:
115	        existing?.model ??
116	        resolveModelSlug(project.defaultModel ?? DEFAULT_MODEL_BY_PROVIDER.codex),
117	      expanded:
118	        existing?.expanded ??
119	        (persistedExpandedProjectCwds.size > 0
120	          ? persistedExpandedProjectCwds.has(project.workspaceRoot)
121	          : true),
122	      scripts: project.scripts.map((script) => ({ ...script })),
123	    };
124	  });
125	}
126	
127	function toLegacySessionStatus(
128	  status: OrchestrationSessionStatus,
129	): "connecting" | "ready" | "running" | "error" | "closed" {
130	  switch (status) {
131	    case "starting":
132	      return "connecting";
133	    case "running":
134	      return "running";
135	    case "error":
136	      return "error";
137	    case "ready":
138	    case "interrupted":
139	      return "ready";
140	    case "idle":
141	    case "stopped":
142	      return "closed";
143	  }
144	}
145	
146	function toLegacyProvider(providerName: string | null): ProviderKind {
147	  if (providerName === "codex") {
148	    return providerName;
149	  }
150	  return "codex";
151	}
152	
153	const CODEX_MODEL_SLUGS = new Set<string>(getModelOptions("codex").map((option) => option.slug));
154	
155	function inferProviderForThreadModel(input: {
156	  readonly model: string;
157	  readonly sessionProviderName: string | null;
158	}): ProviderKind {
159	  if (input.sessionProviderName === "codex") {
160	    return input.sessionProviderName;
161	  }
162	  const normalizedCodex = normalizeModelSlug(input.model, "codex");
163	  if (normalizedCodex && CODEX_MODEL_SLUGS.has(normalizedCodex)) {
164	    return "codex";
165	  }
166	  return "codex";
167	}
168	
169	function resolveWsHttpOrigin(): string {
170	  if (typeof window === "undefined") return "";
171	  const bridgeWsUrl = window.desktopBridge?.getWsUrl?.();
172	  const envWsUrl = import.meta.env.VITE_WS_URL as string | undefined;
173	  const wsCandidate =
174	    typeof bridgeWsUrl === "string" && bridgeWsUrl.length > 0
175	      ? bridgeWsUrl
176	      : typeof envWsUrl === "string" && envWsUrl.length > 0
177	        ? envWsUrl
178	        : null;
179	  if (!wsCandidate) return window.location.origin;
180	  try {
181	    const wsUrl = new URL(wsCandidate);
182	    const protocol =
183	      wsUrl.protocol === "wss:" ? "https:" : wsUrl.protocol === "ws:" ? "http:" : wsUrl.protocol;
184	    return `${protocol}//${wsUrl.host}`;
185	  } catch {
186	    return window.location.origin;
187	  }
188	}
189	
190	function toAttachmentPreviewUrl(rawUrl: string): string {
191	  if (rawUrl.startsWith("/")) {
192	    return `${resolveWsHttpOrigin()}${rawUrl}`;
193	  }
194	  return rawUrl;
195	}
196	
197	function attachmentPreviewRoutePath(attachmentId: string): string {
198	  return `/attachments/${encodeURIComponent(attachmentId)}`;
199	}
200	
201	// ── Pure state transition functions ────────────────────────────────────
202	
203	export function syncServerReadModel(state: AppState, readModel: OrchestrationReadModel): AppState {
204	  const projects = mapProjectsFromReadModel(
205	    readModel.projects.filter((project) => project.deletedAt === null),
206	    state.projects,
207	  );
208	  const existingThreadById = new Map(state.threads.map((thread) => [thread.id, thread] as const));
209	  const threads = readModel.threads
210	    .filter((thread) => thread.deletedAt === null)
211	    .map((thread) => {
212	      const existing = existingThreadById.get(thread.id);
213	      return {
214	        id: thread.id,
215	        codexThreadId: null,
216	        projectId: thread.projectId,
217	        title: thread.title,
218	        model: resolveModelSlugForProvider(
219	          inferProviderForThreadModel({
220	            model: thread.model,
221	            sessionProviderName: thread.session?.providerName ?? null,
222	          }),
223	          thread.model,
224	        ),
225	        runtimeMode: thread.runtimeMode,
226	        interactionMode: thread.interactionMode,
227	        session: thread.session
228	          ? {
229	              provider: toLegacyProvider(thread.session.providerName),
230	              status: toLegacySessionStatus(thread.session.status),
231	              orchestrationStatus: thread.session.status,
232	              activeTurnId: thread.session.activeTurnId ?? undefined,
233	              createdAt: thread.session.updatedAt,
234	              updatedAt: thread.session.updatedAt,
235	              ...(thread.session.lastError ? { lastError: thread.session.lastError } : {}),
236	            }
237	          : null,
238	        messages: thread.messages.map((message) => {
239	          const attachments = message.attachments?.map((attachment) => ({
240	            type: "image" as const,
241	            id: attachment.id,
242	            name: attachment.name,
243	            mimeType: attachment.mimeType,
244	            sizeBytes: attachment.sizeBytes,
245	            previewUrl: toAttachmentPreviewUrl(attachmentPreviewRoutePath(attachment.id)),
246	          }));
247	          const normalizedMessage: ChatMessage = {
248	            id: message.id,
249	            role: message.role,
250	            text: message.text,
251	            createdAt: message.createdAt,
252	            streaming: message.streaming,
253	            ...(message.streaming ? {} : { completedAt: message.updatedAt }),
254	            ...(attachments && attachments.length > 0 ? { attachments } : {}),
255	          };
256	          return normalizedMessage;
257	        }),
258	        proposedPlans: thread.proposedPlans.map((proposedPlan) => ({
259	          id: proposedPlan.id,
260	          turnId: proposedPlan.turnId,
261	          planMarkdown: proposedPlan.planMarkdown,
262	          createdAt: proposedPlan.createdAt,
263	          updatedAt: proposedPlan.updatedAt,
264	        })),
265	        error: thread.session?.lastError ?? null,
266	        createdAt: thread.createdAt,
267	        latestTurn: thread.latestTurn,
268	        lastVisitedAt: existing?.lastVisitedAt ?? thread.updatedAt,
269	        branch: thread.branch,
270	        worktreePath: thread.worktreePath,
271	        turnDiffSummaries: thread.checkpoints.map((checkpoint) => ({
272	          turnId: checkpoint.turnId,
273	          completedAt: checkpoint.completedAt,
274	          status: checkpoint.status,
275	          assistantMessageId: checkpoint.assistantMessageId ?? undefined,
276	          checkpointTurnCount: checkpoint.checkpointTurnCount,
277	          checkpointRef: checkpoint.checkpointRef,
278	          files: checkpoint.files.map((file) => ({ ...file })),
279	        })),
280	        activities: thread.activities.map((activity) => ({ ...activity })),
281	      };
282	    });
283	  return {
284	    ...state,
285	    projects,
286	    threads,
287	    threadsHydrated: true,
288	  };
289	}
