import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "./ThemeProvider";

/** Small swatch showing three representative theme surface colors. */
function ThemeSwatch({ theme }: { theme: Theme }) {
  return (
    <div className="flex h-8 w-14 shrink-0 overflow-hidden rounded-md border border-border">
      <div className="flex-1" style={{ background: theme.colors.sidebar }} />
      <div className="flex-[2]" style={{ background: theme.colors.editor }} />
      <div
        className="w-1.5"
        style={{ background: theme.colors.accent }}
      />
    </div>
  );
}

/**
 * Theme selector with preview swatches for every available theme.
 * Drop this into any settings surface — it reads and writes state
 * through the ThemeProvider context.
 */
export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => {
        const selected = activeTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatch theme={t} />

            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs opacity-70">
                {t.id}
              </span>
            </span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

