import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

// ── Constants ───────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

// ── Helpers ─────────────────────────────────────────────────────────

/** Resolve perceived brightness to determine light vs dark color scheme. */
function isDarkBackground(hex: string): boolean {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

function getStoredThemeId(): string {
  try {
    return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
  } catch {
    return DEFAULT_THEME_ID;
  }
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

/** Derive "light" | "dark" from a theme's background color. */
export function resolveColorScheme(theme: Theme): "light" | "dark" {
  return isDarkBackground(theme.colors.background) ? "dark" : "light";
}

// CSS custom properties that map directly to existing app variables so
// every theme selection is immediately reflected across all components.
const THEME_TO_APP_VARIABLES: ReadonlyArray<[keyof Theme["colors"], string]> = [
  ["background", "--background"],
  ["foreground", "--foreground"],
  ["accent", "--primary"],
  ["accent", "--ring"],
];

// Additional namespaced properties for region-specific surfaces.
const THEME_REGION_VARIABLES: ReadonlyArray<[keyof Theme["colors"], string]> = [
  ["sidebar", "--theme-sidebar"],
  ["editor", "--theme-editor"],
  ["terminal", "--theme-terminal"],
  ["statusBar", "--theme-status-bar"],
];

function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle dark-mode class based on perceived background brightness
  root.classList.toggle("dark", isDarkBackground(theme.colors.background));

  // Override core app CSS variables (highest specificity via inline style)
  for (const [colorKey, cssProp] of THEME_TO_APP_VARIABLES) {
    root.style.setProperty(cssProp, theme.colors[colorKey]);
  }

  // Set region-specific custom properties
  for (const [colorKey, cssProp] of THEME_REGION_VARIABLES) {
    root.style.setProperty(cssProp, theme.colors[colorKey]);
  }

  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force reflow so the transition suppression takes effect
    void root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// ── Eagerly apply the stored theme on module load (prevents flash) ──
applyThemeToDOM(resolveTheme(getStoredThemeId()));

// ── Context ─────────────────────────────────────────────────────────

interface ThemeContextValue {
  /** The active theme object. */
  theme: Theme;
  /** Switch to a different theme by ID. */
  setTheme: (id: string) => void;
  /** All built-in themes. */
  availableThemes: readonly Theme[];
  /** Resolved color scheme ("light" | "dark") derived from the active theme. */
  resolvedTheme: "light" | "dark";
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() =>
    resolveTheme(getStoredThemeId()),
  );

  const setTheme = useCallback((id: string) => {
    const next = resolveTheme(id);
    try {
      localStorage.setItem(STORAGE_KEY, next.id);
    } catch {
      // Ignore quota / storage errors.
    }
    applyThemeToDOM(next, true);
    setThemeState(next);
  }, []);

  // Keep DOM in sync on mount and when theme changes
  useEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  // Cross-tab synchronisation via storage events
  useEffect(() => {
    const handler = (e: StorageEvent) => {
      if (e.key === STORAGE_KEY) {
        const next = resolveTheme(e.newValue ?? DEFAULT_THEME_ID);
        applyThemeToDOM(next, true);
        setThemeState(next);
      }
    };
    window.addEventListener("storage", handler);
    return () => window.removeEventListener("storage", handler);
  }, []);

  const value: ThemeContextValue = {
    theme,
    setTheme,
    availableThemes: listThemes(),
    resolvedTheme: resolveColorScheme(theme),
  };

  return <ThemeContext value={value}>{children}</ThemeContext>;
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

